from langgraph.graph import StateGraph, END
from typing import TypedDict, Literal
from langchain_core.documents import Document

class CRAGState(TypedDict):
    query:          str
    retrieved_docs: list[Document]
    verdicts:       list[tuple[Document, RelevanceVerdict]]
    action:         str               # "use" | "both" | "web"
    context_texts:  list[str]
    answer:         str

def retrieve_node(state: CRAGState) -> CRAGState:
    docs = vectorstore.similarity_search(state["query"], k=5)
    return {**state, "retrieved_docs": docs}

def evaluate_node(state: CRAGState) -> CRAGState:
    verdicts, action = evaluate_retrieved_docs(state["query"], state["retrieved_docs"])
    return {**state, "verdicts": verdicts, "action": action}

def route_action(state: CRAGState) -> Literal["use_docs", "web_search", "combine"]:
    return {"use": "use_docs", "web": "web_search", "both": "combine"}[state["action"]]

def use_docs_node(state: CRAGState) -> CRAGState:
    texts = [
        refine_document(state["query"], doc.page_content)
        for doc, v in state["verdicts"]
        if v.relevance in (Relevance.CORRECT, Relevance.AMBIGUOUS)
    ]
    return {**state, "context_texts": texts}

def web_search_node(state: CRAGState) -> CRAGState:
    snippets = web_search_fallback(state["query"])
    return {**state, "context_texts": snippets}

def combine_node(state: CRAGState) -> CRAGState:
    doc_texts = [
        doc.page_content for doc, v in state["verdicts"]
        if v.relevance in (Relevance.CORRECT, Relevance.AMBIGUOUS)
    ]
    web_texts = web_search_fallback(state["query"])
    return {**state, "context_texts": doc_texts + web_texts}

def generate_node(state: CRAGState) -> CRAGState:
    context = "\n\n".join(state["context_texts"])
    gen_prompt = ChatPromptTemplate.from_messages([
        ("system", "Answer using only the context below.\nContext: {ctx}"),
        ("human", "{q}"),
    ])
    answer = (gen_prompt | llm | StrOutputParser()).invoke({
        "ctx": context, "q": state["query"]
    })
    return {**state, "answer": answer}

# Build the graph
graph = StateGraph(CRAGState)
graph.add_node("retrieve", retrieve_node)
graph.add_node("evaluate", evaluate_node)
graph.add_node("use_docs", use_docs_node)
graph.add_node("web_search", web_search_node)
graph.add_node("combine", combine_node)
graph.add_node("generate", generate_node)

graph.set_entry_point("retrieve")
graph.add_edge("retrieve", "evaluate")
graph.add_conditional_edges("evaluate", route_action, {
    "use_docs":   "use_docs",
    "web_search": "web_search",
    "combine":    "combine",
})
graph.add_edge("use_docs",   "generate")
graph.add_edge("web_search", "generate")
graph.add_edge("combine",    "generate")
graph.add_edge("generate", END)

crag_app = graph.compile()
result = crag_app.invoke({"query": "What caused Q3 cloud revenue growth?"})
print(result["answer"])

from sentence_transformers import CrossEncoder

relevance_scorer = CrossEncoder("cross-encoder/ms-marco-MiniLM-L-6-v2", max_length=512)

def lightweight_crag(
    query: str,
    vectorstore,
    k: int = 5,
    correct_threshold: float = 3.0,    # logit threshold for "correct"
    incorrect_threshold: float = -1.0, # below this → "incorrect"
) -> str:
    docs = vectorstore.similarity_search(query, k=k)
    if not docs:
        context_texts = web_search_fallback(query)
    else:
        scores = relevance_scorer.predict(
            [(query, doc.page_content) for doc in docs]
        )
        max_score = max(scores)

        if max_score >= correct_threshold:
            action = "use"
        elif max_score >= incorrect_threshold:
            action = "both"
        else:
            action = "web"

        print(f"Max relevance score: {max_score:.2f} → {action}")
        context_texts = []
        if action in ("use", "both"):
            context_texts = [
                docs[i].page_content
                for i, s in enumerate(scores)
                if s >= incorrect_threshold
            ]
        if action in ("web", "both"):
            context_texts.extend(web_search_fallback(query))

    context = "\n\n".join(context_texts)
    gen_prompt = ChatPromptTemplate.from_messages([
        ("system", "Answer using only the context.\nContext: {ctx}"),
        ("human", "{q}"),
    ])
    return (gen_prompt | llm | StrOutputParser()).invoke({"ctx": context, "q": query})
